def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    ppt = Presentation(modified_ppt_path)
    slide = ppt.slides[2] if len(ppt.slides) > 2 else None
    if not slide:
        return "Slide 3 does not exist.", 0.0

    # Extract text from all shapes on the slide to check for labels
    all_text = ""
    for shape in slide.shapes:
        try:
            if hasattr(shape, 'text_frame') and shape.text_frame:
                all_text += shape.text_frame.text.lower() + " "
        except:
            pass

    # Check for accounting-related terms (more flexible since this is non-critical)
    accounting_terms = ['assets', 'capital', 'liabilities', 'asset', 'liability', 'equity', 'debit', 'credit', 'equation', 'balance']
    found_terms = [term for term in accounting_terms if term in all_text]

    # More flexible scoring since this is non-critical
    if len(found_terms) >= 3:
        return f"Multiple accounting terms found on slide ({len(found_terms)} terms), suggesting accounting context.", 1.0
    elif len(found_terms) >= 1:
        return f"Some accounting terms found ({len(found_terms)} terms), partial context present.", 0.7
    else:
        return "No clear accounting terms found, but SmartArt may still represent the concept visually.", 0.4

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    ppt = Presentation(modified_ppt_path)
    slide = ppt.slides[2] if len(ppt.slides) > 2 else None
    if not slide:
        return "Slide 3 does not exist.", 0.0

    # Look for SmartArt/Diagram shapes
    smartart_shapes = []
    for shape in slide.shapes:
        if (hasattr(shape, 'name') and 'diagram' in shape.name.lower()) or \
           (shape.shape_type is None) or \
           (hasattr(shape, 'name') and any(term in shape.name.lower() for term in ['smartart', 'chart', 'graphic'])):
            smartart_shapes.append(shape)

    if not smartart_shapes:
        return "No SmartArt/Diagram present on slide 3.", 0.0

    # Use VLM to check if the slide contains a balance/scale image
    # First find the slide 3 screenshot
    slide_screenshot = None
    for s in modified_ppt_screenshots:
        if s.slide_number == 3:
            slide_screenshot = s.image_path
            break

    if slide_screenshot:
        vlm_prompt = """Look at this PowerPoint slide image. Does it contain a visual representation of a balance, scale, or weighing device that could represent the accounting equation concept of balance between assets and liabilities/equity?

Look for:
- Scale/balance imagery (traditional weighing scales)
- Seesaw or balance beam representations  
- Any visual metaphor showing balance or equilibrium
- Diagrams showing equal sides or balanced elements

Answer with 'YES' if you can see clear balance/scale imagery that represents the accounting equation balance concept, or 'NO' if there is no such visual representation."""

        try:
            vlm_response = vlm_call(vlm_prompt, [slide_screenshot], temperature=0.2, max_tokens=50)
            if vlm_response and 'yes' in vlm_response.lower():
                return "VLM confirms SmartArt contains balance/scale imagery representing the accounting equation balance.", 1.0
            else:
                # Fallback to text-based check if VLM doesn't detect visual balance
                balance_keywords = ['balance', 'weigh', 'scales', '=', 'equation', 'assets', 'capital', 'liabilities']

                for shape in smartart_shapes:
                    shape_text = ''
                    # Try to extract text from the SmartArt
                    try:
                        if hasattr(shape, 'text_frame') and shape.text_frame:
                            shape_text += shape.text_frame.text.lower() + ' '
                    except:
                        pass

                    # Check for balance/equation indicators in text
                    count = sum(1 for k in balance_keywords if k in shape_text)
                    if count >= 2:
                        return "SmartArt contains balance-related text but no clear visual balance imagery detected by VLM.", 0.7

                return "SmartArt/Diagram present but VLM confirms no clear balance/scale imagery or sufficient balance-related content.", 0.3

        except Exception as e:
            # Fallback to original logic if VLM fails
            balance_keywords = ['balance', 'weigh', 'scales', '=', 'equation', 'assets', 'capital', 'liabilities']

            for shape in smartart_shapes:
                shape_text = ''
                try:
                    if hasattr(shape, 'text_frame') and shape.text_frame:
                        shape_text += shape.text_frame.text.lower() + ' '
                except:
                    pass

                count = sum(1 for k in balance_keywords if k in shape_text)
                if count >= 2 or ('balance' in shape.name.lower() if hasattr(shape, 'name') else False):
                    return "SmartArt likely reflects balance relationship (VLM check failed, used text analysis).", 0.8

            return "SmartArt structure appears suitable for representing balance (VLM check failed).", 0.6
    else:
        # No screenshot available, fall back to text analysis
        balance_keywords = ['balance', 'weigh', 'scales', '=', 'equation', 'assets', 'capital', 'liabilities']

        for shape in smartart_shapes:
            shape_text = ''
            try:
                if hasattr(shape, 'text_frame') and shape.text_frame:
                    shape_text += shape.text_frame.text.lower() + ' '
            except:
                pass

            count = sum(1 for k in balance_keywords if k in shape_text)
            if count >= 2 or ('balance' in shape.name.lower() if hasattr(shape, 'name') else False):
                return "SmartArt likely reflects balance relationship (no screenshot available for VLM).", 0.8

        return "SmartArt structure appears suitable for representing balance (no screenshot available).", 0.6

